      "guidedPracticeObjective": "Calculate the resistance of a heating element that draws 10A of current when connected to a 230V supply.",
      "practiceObjective": "Determine the total power (in Watts) consumed by a circuit where the voltage is 230V and the resistance is 20 ohms.",
      "integrativeObjective": "Describe the effect on the circuit current if the resistance is doubled while the supply voltage remains constant."
    }
  ]
}

{
  "moduleTitle": "2365 Unit 203 Protective Measures",
  "blueprints": [
    {
      "lessonCode": "203-4A",
      "title": "203-4A - Earthing Systems and ADS Components",
      "unit": "Unit 203",
      "topic": "Earthing systems and ADS components",
      "objectiveSummary": "Identify TN-S, TN-C-S, and TT earthing arrangements and explain how ADS components ensure safety.",
      "focusText": "Earthing systems are classified as TN-S (separate earth/neutral), TN-C-S (combined neutral/earth), and TT (earth electrode). Automatic Disconnection of Supply (ADS) relies on the Circuit Protective Conductor (CPC) and protective devices to clear faults quickly. The total loop impedance (Zs) determines if the device will trip within the required time.",
      "sourceRefs": [
        "203-4A"
      ],
      "teachChecks": [
        {
          "title": "Earthing Arrangements",
          "objective": "Distinguish between TN-S, TN-C-S, and TT systems based on their connection to the supplier's earth."
        },
        {
          "title": "ADS and the CPC",
          "objective": "Explain the role of the Circuit Protective Conductor and protective devices in achieving safe disconnection."
        }
      ],
      "workedExampleObjective": "Identify an earthing system by examining the incoming supply cable and the presence of an earth electrode.",
      "guidedPracticeObjective": "Given a diagram of a supply with a combined neutral and earth conductor (PEN), identify the system type and the specific ADS components required.",
      "practiceObjective": "Categorize three different installation scenarios into TN-S, TN-C-S, or TT and list the primary protective device used in each.",
      "integrativeObjective": "Describe the complete path a fault current takes from a live conductor through the CPC to trigger the protective device in a TN-S system."
    },
    {
      "lessonCode": "203-4C",
      "title": "203-4C - Earth Loop Impedance Path",
      "unit": "Unit 203",
      "topic": "Earth loop impedance path",
      "objectiveSummary": "Calculate total earth fault loop impedance (Zs) and explain the relationship between impedance and disconnection speed.",
      "focusText": "The earth fault loop impedance path consists of the supplier side (Ze) and the installation side (R1 + R2). The formula is Zs = Ze + (R1 + R2). Impedance must be low enough to allow sufficient fault current to flow, ensuring the protective device operates fast enough to prevent danger.",
      "sourceRefs": [
        "203-4C"
      ],
      "teachChecks": [
        {
          "title": "Components of the Loop",
          "objective": "Define Ze, R1, and R2 and identify which parts belong to the supplier versus the installation."
        },
        {
          "title": "Impedance and Safety",
          "objective": "Explain why low impedance is necessary for fast disconnection of the supply."
        }
      ],
      "workedExampleObjective": "Calculate the total earth fault loop impedance (Zs) using the formula Zs = Ze + (R1 + R2) with provided test values.",
      "guidedPracticeObjective": "Calculate Zs for a final circuit where the external impedance (Ze) is 0.35 ohms and the circuit conductors (R1 + R2) measure 1.1 ohms.",
      "practiceObjective": "Determine the total Zs for a TT system with a Ze of 45 ohms and an (R1 + R2) of 0.5 ohms, then explain if this value is typically higher or lower than a TN system.",
      "integrativeObjective": "Summarize how the relationship between Ze and (R1 + R2) affects the total Zs and why this value is critical for the safety of the installation."
    }
  ]
}
